{
  "verses": [
    {
      "n": 18,
      "column": "left",
      "text": "Un Kaäta Behrni bija:\nAmrams/ un Jezeaṙs/ un Ee-\nbrons/ un Uṣiels.\n"
    },
    {
      "n": 19,
      "column": "left",
      "text": "Un tee Behrni Merara\nbija : Maėlus un Musus. Un\nfchee irr to Lewitu Raddi pehz\nwixxu Tehweem.\n"
    },
    {
      "n": 20,
      "column": "left",
      "text": "Gersona Dehls bija Lib-\nnuṣ/ ta Dehls bija Jakats/ ta\nDehls bija Simus.\n"
    },
    {
      "n": 21,
      "column": "left",
      "text": "Ta Dehls bija Joaks/ ta\nDehls bija Jodns/ ta Dehls bija\nSeerus/ta Dehls bija Jeatrains.\n"
    },
    {
      "n": 22,
      "column": "left",
      "text": "Kaäta Behrni btja: Am-\nminadabs/ ta Dehls bija Korus/\nta Dehls bija Afirs.\n"
    },
    {
      "n": 23,
      "column": "left",
      "text": "Ta Dehls bija Elkanus/\nta Dehls bija Abi-Aṣaws/ ta\nDehls bija Afirs.\n"
    },
    {
      "n": 24,
      "column": "left",
      "text": "Ta Dehls bija Tääts/ ta\nDehls bija Uriels/ ta Dehls bija\nUsijus/ ta Dehls bija Sauls.\n"
    },
    {
      "n": 25,
      "column": "left",
      "text": "Un Elkanus Behrni bija:\nAmasajus un Afimots.\n"
    },
    {
      "n": 26,
      "column": "left",
      "text": "Ta Dehls bija Elkanus/\nta Dehls bija Elkanus no Zo-\nwäs/ ta Dehls bija Nääts.\n"
    },
    {
      "n": 27,
      "column": "left",
      "text": "Ta Dehls btja Elijas/\nta Dehls btja Jeroams/ ta Dehls\nbija Elkanus.\n"
    },
    {
      "n": 28,
      "column": "left",
      "text": "Un Samuteka Behrni bi-\nja: Tas pirmosintajs Wasaus\nun Abijus.\n"
    },
    {
      "n": 29,
      "column": "left",
      "text": "Merara Behrni btja:\nMaėlus/ ta Dehls btja Libmus/\nta Dehls bija Simejus/ ta Dehls\nbtja Usus.\n"
    },
    {
      "n": 30,
      "column": "left",
      "text": "Ta Dehls bija Simens/\nta Dehls bija Aggijus/ ta Dehls\nbtja Atajus.\n"
    },
    {
      "n": 31,
      "column": "right",
      "text": "Un fchee irr tee/ ko Dah-\nwids cezehle par Dseedatajeem ta\nKUNGA Namma/ kur tas\nSchkirsts duṣteja.\n"
    },
    {
      "n": 32,
      "column": "right",
      "text": "Un tee kalpoja preeksch\ntahs Sa-eefchanas Zelts Dsh-\nwokta ar Dseedatchanahm/ tee-\nkams Salamans ta KUNGA\nNammu Jerusaleine ustaifija.\nUn tee stahweja pehz fawu Ge-\nraddutnu eeksch fawas Kalpo-\nschanas.\n"
    },
    {
      "n": 33,
      "column": "right",
      "text": "Un fchee irr/ kas stahwe-\nja ar saweem Behrneem. No\nto Kaätiteyu Behrneein Gemans\ntas Dseedatajs/ Joėta Dehls/ ta\nDehla Samueła.\n"
    },
    {
      "n": 34,
      "column": "right",
      "text": "Ta Dehla Elkanus/ ta\nDehla Jeroama/ ta Dehla Eli-\neka/ ta Dehla Touṣ.\n"
    },
    {
      "n": 35,
      "column": "right",
      "text": "Ta Dehla Zuwa/ ta Deh-\nla Elkanus/ ta Dehla Maita/ ta\nDehla Amasaja.\n"
    },
    {
      "n": 36,
      "column": "right",
      "text": "Ta Dehla Elkanus/ ta\nDehla Joėka/ ta Dehla Asarijus/\nta Dehla Zewanijs.\n"
    },
    {
      "n": 37,
      "column": "right",
      "text": "Ta Dehla Takata/ ta\nDehla Affira/ ta Dehla Abi-Aṣ-\njawa/ ta Dehla Korus.\n"
    },
    {
      "n": 38,
      "column": "right",
      "text": "Ta Dehla Jezeara/ ta\nDehla Kaäta/ ta Dehla Lewja/\nIsraėta Dehla.\n"
    },
    {
      "n": 39,
      "column": "right",
      "text": "Un wiṣka Brahlts Aṣaws\nstahweja wiṣain va labbo Roh-\nfu/ Aṣaws bija Berekijs Dehls/\nta Dehla Simeüs.\n"
    },
    {
      "n": 40,
      "column": "right",
      "text": "Ta Dehla Mikaėta/ ta\nDehla Baėsejus/ ta Dehla Mat-\nkijus.\n"
    }
  ],
  "confidence": "high",
  "notes": ""
}
